CREATE TABLE IF NOT EXISTS t_p90995829_dmaxi_site_replica.visits (id SERIAL PRIMARY KEY, user_id INTEGER NOT NULL, visit_number VARCHAR(20) NOT NULL UNIQUE, service VARCHAR(300) NOT NULL, car VARCHAR(200), cost NUMERIC(10,2) NOT NULL DEFAULT 0, bonus_earned INTEGER NOT NULL DEFAULT 0, status VARCHAR(20) NOT NULL DEFAULT 'completed', notes TEXT, created_at TIMESTAMP NOT NULL DEFAULT NOW(), visit_date DATE NOT NULL DEFAULT CURRENT_DATE);